def shout(func):
    def wrapper():
        print(">>>")
        func()
        print("<<<")
    return wrapper

@shout
def greet():
    print("Hello!")

greet()

import functools

def my_decorator(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        result = func(*args, **kwargs)
    return wrapper

@my_decorator
def add(a, b):
    return a + b

print(add(3, 4))

